import React from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import response from './response.json';

interface CurrentBook {
  title: string;
  author: string;
  currentPage: number;
  totalPages: number;
  progress: number;
}

interface ReadingTrackerData {
  yearlyGoal: {
    targetBooks: number;
    booksRead: number;
    progressPercentage: number;
  };
  currentBooks: CurrentBook[];
}

export default function Widget() {
  const readingData = response.data as ReadingTrackerData;
  const { yearlyGoal, currentBooks } = readingData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Yearly Reading Goal
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {yearlyGoal.booksRead} of {yearlyGoal.targetBooks} books
            </Typography>
            <LinearProgress
              variant="determinate"
              value={yearlyGoal.progressPercentage}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#FFE0B2',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#FF5722',
                  borderRadius: 4,
                }
              }}
            />
            <Typography variant="caption" fontWeight={600} sx={{ color: '#FF5722', mt: 1 }}>
              {yearlyGoal.progressPercentage}%
            </Typography>
          </Box>

          {currentBooks.slice(0, 2).map((book, index) => (
            <Box key={index}>
              <Typography variant="body1" fontWeight={500} sx={{ color: '#FF5722' }}>
                {book.title}
              </Typography>
              <Typography variant="caption" color="text.secondary" sx={{ mb: 0.5 }}>
                by {book.author}
              </Typography>
              <LinearProgress
                variant="determinate"
                value={book.progress}
                sx={{
                  height: 8,
                  borderRadius: 4,
                  bgcolor: '#FFE0B2',
                  '& .MuiLinearProgress-bar': {
                    bgcolor: '#FFC107',
                    borderRadius: 4,
                  }
                }}
              />
              <Typography variant="caption" fontWeight={600} sx={{ color: '#FFC107', mt: 1 }}>
                {book.progress}%
              </Typography>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
